	if err != nil {
		return 0.0, fmt.Errorf("script execution error: %w", err)
	}

	// Check for undefined or null result
	if result == nil || goja.IsUndefined(result) || goja.IsNull(result) {
		return 0.0, fmt.Errorf("script must return a number, got undefined or null")
	}

