	vm.Set("order", order)

	// Set up a timer to interrupt the VM if script execution exceeds the limit.
	// This prevents denial-of-service attacks via infinite loops or
	// computationally expensive scripts.
	timer := time.AfterFunc(maxExecutionTime, func() {
		vm.Interrupt("script execution timed out")
	})
	defer timer.Stop()

	// Execute the script
	result, err := vm.RunString(script)
	if err != nil {
		return 0.0, fmt.Errorf("script execution error: %w", err)
	}

	if result == nil || goja.IsUndefined(result) || goja.IsNull(result) {
		return 0.0, fmt.Errorf("script must return a number, got nil/undefined/null")
	}

	// Convert result to float64
	discount, ok := result.Export().(float64)
